
#include "webview/webview.h"
#include "alloy/api.h"
#include <iostream>
#include <string>

const char* bundled_js = "// shell.ts\nfunction parseArgs(cmdStr) {\n  const args = [];\n  let current = \"\";\n  let inQuotes = false;\n  for (let i = 0;i < cmdStr.length; i++) {\n    const c = cmdStr[i];\n    if (c === '\"')\n      inQuotes = !inQuotes;\n    else if (c === \" \" && !inQuotes) {\n      if (current)\n        args.push(current);\n      current = \"\";\n    } else\n      current += c;\n  }\n  if (current)\n    args.push(current);\n  return args;\n}\nfunction $(strings, ...values) {\n  let cmdStr = strings[0];\n  for (let i = 0;i < values.length; i++) {\n    let val = values[i];\n    if (val && typeof val === \"object\" && val.raw)\n      cmdStr += val.raw;\n    else if (typeof val === \"string\")\n      cmdStr += `\"${val.replace(/\"/g, \"\\\\\\\"\")}\"`;\n    else if (val instanceof Response) {} else\n      cmdStr += val;\n    cmdStr += strings[i + 1];\n  }\n  const promise = (async () => {\n    const commands = cmdStr.split(\"|\").map((s) => s.trim());\n    let lastStdout = null;\n    let finalRes = null;\n    for (const cmd of commands) {\n      let actualCmd = cmd;\n      let stdoutRedirect = null;\n      let stderrRedirect = null;\n      if (cmd.includes(\"2>\")) {\n        const parts = cmd.split(\"2>\");\n        actualCmd = parts[0].trim();\n        stderrRedirect = parts[1].trim();\n      } else if (cmd.includes(\">\")) {\n        const parts = cmd.split(\">\");\n        actualCmd = parts[0].trim();\n        stdoutRedirect = parts[1].trim();\n      }\n      const args = parseArgs(actualCmd);\n      const proc = Alloy.spawn(args, { cwd: promise._cwd || $._cwd, env: promise._env || $._env });\n      if (lastStdout) {\n        await proc.stdin.write(lastStdout);\n        await proc.stdin.end();\n      }\n      const exitCode = await proc.exited;\n      const readStream = async (stream) => {\n        const reader = stream.getReader();\n        let out = \"\";\n        while (true) {\n          const { done, value } = await reader.read();\n          if (done)\n            break;\n          out += new TextDecoder().decode(value);\n        }\n        return out;\n      };\n      const stdout = await readStream(proc.stdout);\n      const stderr = await readStream(proc.stderr);\n      lastStdout = stdout;\n      if (exitCode !== 0 && !promise._nothrow)\n        throw new Error(`Command failed: ${actualCmd}\n${stderr}`);\n      finalRes = {\n        exitCode,\n        stdout: Buffer.from(stdout),\n        stderr: Buffer.from(stderr),\n        text: async () => stdout,\n        json: async () => JSON.parse(stdout),\n        lines: async function* () {\n          for (const line of stdout.split(`\n`))\n            if (line)\n              yield line;\n        }\n      };\n    }\n    return finalRes;\n  })();\n  promise.quiet = () => {\n    promise._quiet = true;\n    return promise;\n  };\n  promise.nothrow = () => {\n    promise._nothrow = true;\n    return promise;\n  };\n  promise.text = async () => (await promise).stdout.toString();\n  promise.json = async () => JSON.parse((await promise).stdout.toString());\n  promise.cwd = (path) => {\n    promise._cwd = path;\n    return promise;\n  };\n  promise.env = (vars) => {\n    promise._env = vars;\n    return promise;\n  };\n  return promise;\n}\n$.escape = (s) => s.replace(/[$( )`\"]/g, \"\\\\$&\");\n$.nothrow = () => {\n  $.throws(false);\n};\n$.throws = (v) => {\n  $._throws = v;\n};\n$.cwd = (path) => {\n  $._cwd = path;\n};\n$.env = (vars) => {\n  $._env = vars;\n};\n// sqlite.ts\nclass Statement {\n  constructor(dbId, sql, dbOptions) {\n    this.dbId = dbId;\n    this.sql = sql;\n    this.dbOptions = dbOptions;\n    this.id = window.__alloy_sqlite_query(dbId, sql);\n    if (this.id.startsWith(\"{\"))\n      throw new Error(JSON.parse(this.id).error);\n    this.columnNames = [];\n    this.columnTypes = [];\n    this.paramsCount = 0;\n  }\n  _process(row) {\n    if (!row)\n      return;\n    const obj = JSON.parse(row);\n    for (const key in obj) {\n      if (obj[key] && typeof obj[key] === \"object\" && obj[key].__blob) {\n        const hex = obj[key].__blob;\n        const bytes = new Uint8Array(hex.length / 2);\n        for (let i = 0;i < hex.length; i += 2)\n          bytes[i / 2] = parseInt(hex.substring(i, i + 2), 16);\n        obj[key] = bytes;\n      } else if (typeof obj[key] === \"string\" && obj[key].endsWith(\"n\")) {\n        obj[key] = BigInt(obj[key].slice(0, -1));\n      }\n    }\n    if (this._asClass) {\n      const instance = Object.create(this._asClass.prototype);\n      Object.assign(instance, obj);\n      return instance;\n    }\n    return obj;\n  }\n  _bind(params) {\n    window.__alloy_sqlite_reset(this.id);\n    params.forEach((p, i) => {\n      window.__alloy_sqlite_bind(this.id, i + 1, p === null ? \"null\" : p.toString());\n    });\n  }\n  get(...params) {\n    this._bind(params);\n    return this._process(window.__alloy_sqlite_step(this.id, !!this.dbOptions.safeIntegers));\n  }\n  all(...params) {\n    this._bind(params);\n    const results = [];\n    let res;\n    while (res = window.__alloy_sqlite_step(this.id, !!this.dbOptions.safeIntegers)) {\n      results.push(this._process(res));\n    }\n    return results;\n  }\n  run(...params) {\n    this._bind(params);\n    const res = window.__alloy_sqlite_step(this.id, !!this.dbOptions.safeIntegers);\n    return { lastInsertRowid: 0, changes: 0 };\n  }\n  values(...params) {\n    const rows = this.all(...params);\n    return rows.map((r) => Object.values(r));\n  }\n  finalize() {\n    window.__alloy_sqlite_reset(this.id);\n  }\n  toString() {\n    return this.sql;\n  }\n  as(Cls) {\n    this._asClass = Cls;\n    return this;\n  }\n}\n\nclass Database {\n  constructor(filename, options = {}) {\n    this.options = options;\n    this.id = window.__alloy_sqlite_open(filename || \":memory:\");\n    if (this.id.startsWith(\"{\"))\n      throw new Error(JSON.parse(this.id).error);\n  }\n  query(sql) {\n    return new Statement(this.id, sql, this.options);\n  }\n  prepare(sql) {\n    return this.query(sql);\n  }\n  run(sql, params = []) {\n    return this.query(sql).run(...Array.isArray(params) ? params : [params]);\n  }\n  close(throwOnError = false) {\n    window.__alloy_sqlite_close(this.id);\n  }\n  serialize() {\n    const hex = window.__alloy_sqlite_serialize(this.id);\n    const bytes = new Uint8Array(hex.length / 2);\n    for (let i = 0;i < hex.length; i += 2)\n      bytes[i / 2] = parseInt(hex.substring(i, i + 2), 16);\n    return bytes;\n  }\n  fileControl(op, value) {\n    return window.__alloy_sqlite_file_control(this.id, op, value);\n  }\n  loadExtension(path) {\n    return window.__alloy_sqlite_load_extension(this.id, path);\n  }\n  transaction(fn) {\n    const t = (args) => {\n      this.run(\"BEGIN\");\n      try {\n        const res = fn(args);\n        this.run(\"COMMIT\");\n        return res;\n      } catch (e) {\n        this.run(\"ROLLBACK\");\n        throw e;\n      }\n    };\n    t.deferred = (args) => {\n      this.run(\"BEGIN DEFERRED\");\n      try {\n        const res = fn(args);\n        this.run(\"COMMIT\");\n        return res;\n      } catch (e) {\n        this.run(\"ROLLBACK\");\n        throw e;\n      }\n    };\n    t.immediate = (args) => {\n      this.run(\"BEGIN IMMEDIATE\");\n      try {\n        const res = fn(args);\n        this.run(\"COMMIT\");\n        return res;\n      } catch (e) {\n        this.run(\"ROLLBACK\");\n        throw e;\n      }\n    };\n    t.exclusive = (args) => {\n      this.run(\"BEGIN EXCLUSIVE\");\n      try {\n        const res = fn(args);\n        this.run(\"COMMIT\");\n        return res;\n      } catch (e) {\n        this.run(\"ROLLBACK\");\n        throw e;\n      }\n    };\n    return t;\n  }\n}\nexport {\n  Database,\n  $\n};\n";

int main() {
    try {
        webview::webview w(true, nullptr);
        w.set_title("AlloyScript Host");
        w.set_size(1280, 800, WEBVIEW_HINT_NONE);
        w.init(bundled_js);
        w.set_html("<html><head><style>body { background: #111; color: #eee; font-family: sans-serif; }</style></head><body><h1>AlloyScript Runtime</h1><div id='app'></div><script>" + std::string(bundled_js) + "</script></body></html>");
        w.run();
    } catch (const webview::exception &e) {
        std::cerr << "Runtime Error: " << e.what() << std::endl;
        return 1;
    }
    return 0;
}
